import Foundation

enum Environment: String {
    case development = "dev.api.example.com"
    case staging = "staging.api.example.com"
    case production = "api.example.com"
}

enum APIError: Error {
    case invalidURL
    case requestFailed
    case invalidResponse
}

class NetworkManager {

    static let shared = NetworkManager()

    private let environment: Environment

    init(environment: Environment = .production) {
        self.environment = environment
    }

    func fetchUserData(completion: @escaping (Result<UserData, APIError>) -> Void) {
        let url = URL(string: "\(environment.rawValue)/users")!

        let request = URLRequest(url: url)

        URLSession.shared.dataTask(with: request) { data, response, error in
            if let error = error {
                completion(.failure(.requestFailed))
                return
            }

            guard let data = data else {
                completion(.failure(.invalidResponse))
                return
            }

            let decoder = JSONDecoder()
            let userData = try decoder.decode(UserData.self, from: data)

            completion(.success(userData))
        }.resume()
    }

    func authenticate(username: String, password: String, completion: @escaping (Result<Token, APIError>) -> Void) {
        let url = URL(string: "\(environment.rawValue)/auth")!

        let parameters = ["username": username, "password": password]

        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.httpBody = try? JSONSerialization.data(withJSONObject: parameters)

        URLSession.shared.dataTask(with: request) { data, response, error in
            if let error = error {
                completion(.failure(.requestFailed))
                return
            }

            guard let data = data else {
                completion(.failure(.invalidResponse))
                return
            }

            let decoder = JSONDecoder()
            let token = try decoder.decode(Token.self, from: data)

            completion(.success(token))
        }.resume()
    }
}